<template>
	<view class="container">
		<!-- 标题 -->
		<Mtitle title="Home"></Mtitle>

		<!-- 用户信息卡片 -->
		<view class="box">
			<!-- 加载中 -->
			<view v-if="loading" style="text-align: center; padding: 20px;">
				<text>加载中...</text>
			</view>
			<!-- 加载完成，显示卡片 -->
			<personalCard v-else :name="userInfo.username" :uid="userInfo.uid" :content="userInfo.brief || '暂无简介'">
			</personalCard>
		</view>

		<!-- 功能导航 -->
		<view class="box">
			<navigator url="/pages/contacts/contacts">
				<messageBar color="#ff5733" content="联系人"></messageBar>
			</navigator>
			<navigator url="/pages/buy/buy">
				<messageBar color="#ac33c1" content="购买订单"></messageBar>
			</navigator>
			<navigator url="/pages/supply/supply">
				<messageBar color="#00baad" content="供应订单"></messageBar>
			</navigator>
			<navigator url="/pages/orders/orders">
				<messageBar color="#d43030" content="全部订单"></messageBar>
			</navigator>
			<navigator url="/pages/stocks/stocks">
				<messageBar color="#2a82e4" content="库存"></messageBar>
			</navigator>
		</view>

		<!-- 其他 -->
		<view class="box">
			<navigator url="#">
				<messageBar color="#ffeb3b" content="创建联系人"></messageBar>
			</navigator>
			<navigator url="#">
				<messageBar color="#a5d63f" content="创建订单"></messageBar>
			</navigator>
		</view>
	</view>
</template>

<script setup>
	import {
		onMounted,
		ref
	} from 'vue'
	import {
		decodeToken
	} from '@/utils/jwt.js'
	// 1. 定义响应式数据
	const userInfo = ref({})
	const loading = ref(true)

	// 2. 获取用户信息
	const getUserInfo = async () => {
		loading.value = true

		try {
			const token = uni.getStorageSync('token')
			const decoded = decodeToken(token)
			if (!decoded) return

			const userId = decoded.userId || decoded.uid || decoded.id
			if (!token) {
				uni.showToast({
					title: '请先登录',
					icon: 'none'
				})
				return
			}

			const res = await uni.request({
				url: `http://localhost:5000/api/users/users/${userId}`,
				method: 'GET',
				header: {
					'Authorization': `Bearer ${token}`,
					'Content-Type': 'application/json'
				}
			})

			if (res.statusCode === 200) {
				userInfo.value = res.data
				console.log('用户信息:', res.data.data)
			} else {
				uni.showToast({
					title: res.data.message || '获取失败',
					icon: 'none'
				})
			}
		} catch (error) {
			console.error('获取用户信息失败:', error)
			uni.showToast({
				title: '网络错误',
				icon: 'none'
			})
		} finally {
			loading.value = false
		}
	}

	// 3. 页面加载时获取数据
	onMounted(() => {
		getUserInfo()
	})
</script>

<style scoped>
	.container {
		background-image: url('@/static/images/background/屏幕截图 2025-08-11 155826.png');
		background-size: cover;
		background-position: center top;
		background-repeat: no-repeat;
		background-attachment: fixed;
		width: 100%;
		height: 100vh;
	}

	.box {
		margin-top: 30rpx;
	}
</style>